const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
const email=String((body.email||(body.contact&&body.contact.email)||'')).trim().toLowerCase();
if(!email) return [{json:{ok:false,reason:'no email in payload',event:body.event||null}}];
try{
  const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/contacts/records',qs:{filter:'email="'+email+'"',perPage:1,fields:'id'},headers:pbH,json:true});
  const rec=r.items&&r.items[0];
  if(rec){ await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/contacts/records/'+rec.id,headers:pbH,body:{blocklisted:true},json:true}); return [{json:{ok:true,email,action:'updated'}}]; }
  // unknown opt-out: remember it so we never re-contact this address
  await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/contacts/records',headers:pbH,body:{email,source_type:'brevo',blocklisted:true},json:true});
  return [{json:{ok:true,email,action:'created'}}];
}catch(e){ return [{json:{ok:true,email,action:'noop',error:String(e&&e.message||e)}}]; }
